        if match:
            class_name, method_part, params = match.groups()
            # Remove generic info
            method_name = method_part.replace('`1', '').replace('`2', '')
            return (f"Method: {method_name}", class_name)
    elif name.startswith("P:"):
        match = re.search(r"P:Microsoft\.Extensions\.AI\.(\w+)\.(.*?)$", name)
        if match:
            class_name, prop_name = match.groups()
            return (f"Property: {prop_name}", class_name)
    elif name.startswith("T:"):
        match = re.search(r"T:Microsoft\.Extensions\.AI\.(\w+)$", name)
        if match:
            class_name = match.group(1)
            return (f"Type: {class_name}", class_name)
    return None

def show_type_details(target_type):
